    private LayoutInflater inflater;

    public SealAdapter(Context context) {
        this.context = context;
        inflater = LayoutInflater.from(context);
    }

    @NonNull
    @Override
    public SealViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = inflater.inflate(R.layout.seal_item, parent, false);
        SealViewHolder viewHolder = new SealViewHolder(view);
        return viewHolder;
    }

    @Override
    public void onBindViewHolder(@NonNull SealViewHolder holder, int position) {
        Seal seal = seals.get(position);
        holder.textView.setText(seal.getName());
        holder.imageView.setImageResource(seal.getIconId());
        holder.textView.setText(seal.getDescriptiveText());
    }

    @Override
    public int getItemCount() {
        return seals.size();
    }

    static class SealViewHolder extends RecyclerView.ViewHolder {
        TextView textView;
        ImageView imageView;

        SealViewHolder(@NonNull View itemView) {
            super(itemView);
            textView = itemView.findViewById(R.id.seal_name);
            imageView = itemView.findViewById(R.id.seal_icon);
        }
    }

    public void addSeal(Seal seal) {
        seals.add(seal);
        notifyItemChanged(getItemPosition(seal));
    }

    public void removeSeal(Seal seal) {
        seals.remove(seal);
        notifyItemRemoved(getItemPosition(seal));
    }

    private int getItemPosition(Seal seal) {
        return seals.indexOf(seal);
    }
}
